INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", "カリン", 190804, 1, 0, 1, "", 1, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", "", 0, 0, 1, 2, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 3, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", "", 0, 0, 1, 4, "", 2, 0, 2, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", "", 0, 0, 2, 5, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", "", 0, 0, 2, 6, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", "", 0, 0, 2, 7, "", 2, 0, 2, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", "", 0, 0, 3, 8, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", "", 0, 0, 3, 9, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", "", 0, 0, 3, 10, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", "", 0, 0, 3, 11, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", "", 0, 0, 3, 12, "", 2, 0, 2, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", "", 0, 0, 4, 13, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", "", 0, 0, 4, 14, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", "", 0, 0, 4, 15, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", "", 0, 0, 4, 16, "", 2, 0, 1, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", "", 0, 0, 4, 17, "", 2, 0, 2, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", "カリン", 190804, 2, 0, 18, "", 3, 0, 0, 60000, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", "カリン", 190804, 3, 0, 19, "", 3, 0, 0, 60000, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キミと出会ってもう\n1年もたつんだね！\nう～ん、いつも\n寝てばっかりだから、", "ハツネ", 101201, 1, 0, 20, "", 0, 0, 0, 80001, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("少しでも\n寝る時間を減らして\nキミと一緒にいる\n時間増やしたいなぁ♪", "ハツネ", 101201, 2, 0, 21, "", 0, 0, 0, 80001, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなたと知り合ってから\nもう1年…\n時がたつのは\n早いですね", "シオリ", 103801, 1, 0, 22, "", 1, 0, 0, 80001, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("来年も、\n一緒にいられたら…\nうれしいな", "シオリ", 103801, 2, 0, 23, "", 1, 0, 0, 80001, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなたと一緒にいるようになって、\nもう1年ですか…", "キョウカ", 103601, 1, 0, 24, "", 0, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("最初の頃よりも、頼もしく\nなりましたね。私はどうですか？\n成長していますか？", "キョウカ", 103601, 2, 0, 25, "", 0, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おにいちゃんとあってから、\n1年たったよ～！", "ミミ", 102001, 1, 0, 26, "", 1, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ミミね、おにいちゃんと\nいっぱい遊べてたのしかったな～♪\nこれからもずっと\nいっしょにいてね～！", "ミミ", 102001, 2, 0, 27, "", 1, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("にいちゃんがミソギのイタズラに\n引っかかり続けてもう1年かぁ", "ミソギ", 100401, 1, 0, 28, "", 2, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…これからもいっぱいミソギと\n遊んでね、にいちゃん！", "ミソギ", 100401, 2, 0, 29, "", 2, 0, 0, 80001, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もう王子はんと会うてから\n1年ぐらいたつそうどすえ\n早いもんやなあ", "マホ", 101001, 1, 0, 30, "", 0, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("このままやと、\nうちもあっという間に\n干からびてしまいそうどすえ\nなーんてな。うふふ", "マホ", 101001, 2, 0, 31, "", 0, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お主と会って早1年じゃな\nこれからも存分に尽くすがよい", "イリヤ", 104401, 1, 0, 32, "", 1, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わらわもたまには、お主の献身に\n報いてやらぬでもない♪", "イリヤ", 104401, 2, 0, 33, "", 1, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もう、キミと出会って結構な時間が\nたつさ～。でも、私たちの旅は\nまだまだ始まったばかりさ～！", "カオリ", 101701, 1, 0, 34, "", 2, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからも、どうぞよろしく\nお願いするさ～！", "カオリ", 101701, 2, 0, 35, "", 2, 0, 0, 80001, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あんたと出会ってからもうそんなに\nたつのね～", "サレン", 102801, 1, 0, 36, "", 0, 0, 0, 80001, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あっという間だったって感じるほど\n楽しかったわ！\nこれからも一緒に頑張りましょ！", "サレン", 102801, 2, 0, 37, "", 0, 0, 0, 80001, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("出会ってから1年間、ずっと\nご迷惑をかけっぱなしで、\nすみません…", "スズメ", 102501, 1, 0, 38, "", 1, 0, 0, 80001, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからはもっと頑張りますから\n見ていてくださいね\nできれば…\n今までよりも、私の近くで♪", "スズメ", 102501, 2, 0, 39, "", 1, 0, 0, 80001, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("振り返れば、今までいろんなことが\nあったにゃあ…", "タマキ", 104601, 1, 0, 40, "", 0, 0, 0, 80001, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからも、二人でたくさんの\n思い出をがっぽり作っていく\nにゃー！", "タマキ", 104601, 2, 0, 41, "", 0, 0, 0, 80001, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キミとの師弟関係も、\nもう1年なのね…\nでもキミに教えることは、", "ミフユ", 104801, 1, 0, 42, "", 1, 0, 0, 80001, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("まだまだいっぱいあるわ\nこれからも、\nしっかりついて来てね！", "ミフユ", 104801, 2, 0, 43, "", 1, 0, 0, 80001, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなたさまと出会ってもう1年…", "アキノ", 103201, 1, 0, 44, "", 0, 0, 0, 80001, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("光陰矢のごとし、とはまさに\nこのことですわ。…思い出は決して\nお金では買えませんわね", "アキノ", 103201, 2, 0, 45, "", 0, 0, 0, 80001, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ダメな私を1年間も見捨てないで\nくれて、本当にありがとう", "ユカリ", 103401, 1, 0, 46, "", 1, 0, 0, 80001, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("情けないところいっぱいみせるかも\nしれないけど、これからも一緒に\nいてくれると、うれしいな", "ユカリ", 103401, 2, 0, 47, "", 1, 0, 0, 80001, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オマエと出会ってもう1年か\nまさかこのワタシの結婚相手に\nなろうとはな…", "クリスティーナ", 107101, 1, 0, 48, "", 0, 0, 0, 80001, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ともかくこれからも\n愉しませてくれよ☆", "クリスティーナ", 107101, 2, 0, 49, "", 0, 0, 0, 80001, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("君と出会ってからもう1年か。\n以前と比べて私の表情もいくらか\n柔らかくなった気がするんだが、\nどうだろう？", "ジュン", 104701, 1, 0, 50, "", 1, 0, 0, 80001, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("見えないから分からないって？\nそれもそうだな…", "ジュン", 104701, 2, 0, 51, "", 1, 0, 0, 80001, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もう1年たったみたいだね\nあなたをからかってばかりだった\nけど、楽しかった♪", "トモ", 103701, 1, 0, 52, "", 0, 0, 0, 80001, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからもよろしくね！", "トモ", 103701, 2, 0, 53, "", 0, 0, 0, 80001, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("出会って、もう1年たっちゃった\nんスね。なんだか意外ッス", "マツリ", 100501, 1, 0, 54, "", 1, 0, 0, 80001, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("毎日楽しくて、あっという間に過ぎ\nちゃったみたいなんスよね\nこれからも一緒に悪と戦うッス！", "マツリ", 100501, 2, 0, 55, "", 1, 0, 0, 80001, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オマエと会って1年なの！\n全然成仏もできなかったし、", "ミヤコ", 100701, 1, 0, 56, "", 0, 0, 0, 80001, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("生き返りもしなかったけど、\nすごく楽しかったの～♪\nオマエとプリンがあれば、\nミヤコはハッピーなの～♪", "ミヤコ", 100701, 2, 0, 57, "", 0, 0, 0, 80001, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなたと出会って1年なんですね\nでも、私の占いでは、私とあなたは", "シノブ", 103101, 1, 0, 58, "", 1, 0, 0, 80001, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("来年も再来年も一緒にいるようです\nふふ、よろしくお願いしますね", "シノブ", 103101, 2, 0, 59, "", 1, 0, 0, 80001, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("貴様が閃光のシグルドとして覚醒し\nもう1年か…。これからも我らの\n長き戦いに終わりはないが、", "アンナ", 100901, 1, 0, 60, "", 0, 0, 0, 80001, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それでも貴様となら…\n添い遂げる覚悟はできているぞ！", "アンナ", 100901, 2, 0, 61, "", 0, 0, 0, 80001, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("君と出会ってもう1年だって！\n早いねー！", "ナナカ", 101301, 1, 0, 62, "", 1, 0, 0, 80001, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからも最強のバディタッグで\n大活躍だー！\n頼りにしてるよ、相棒！", "ナナカ", 101301, 2, 0, 63, "", 1, 0, 0, 80001, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("1年たつのって、あっという間ね\nまだまだ君の知らない部分が\nたくさんあるし…", "ミツキ", 105101, 1, 0, 64, "", 0, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからも、いろんなところを\n調べさせてね？", "ミツキ", 105101, 2, 0, 65, "", 0, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お前さんと出会ってもう1年か\n助太刀するつもりが", "ルカ", 105601, 1, 0, 66, "", 1, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("逆に助けられたりもしたね\nこれからもよろしく頼むよ！", "ルカ", 105601, 2, 0, 67, "", 1, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("早いものですわね、あなた様と\nお会いして、もう1年…", "エリコ", 102701, 1, 0, 68, "", 2, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなた様といると、時があっと\nいう間に過ぎてしまいます\n時間を止める研究をしなくては\nいけませんね…", "エリコ", 102701, 2, 0, 69, "", 2, 0, 0, 80001, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お兄ちゃんと会ってから、もう、\n1年なんだね。私、少しは\nお姉ちゃんっぽくなったかな？", "アヤネ", 102301, 1, 0, 70, "", 0, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あ、ぷうきちもお兄ちゃんっぽく\nなったよね？", "アヤネ", 102301, 2, 0, 71, "", 0, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あなたと出会って、\nもう1年がたったんですね…\nこれからもそばにいて、", "チカ", 104201, 1, 0, 72, "", 1, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("私のことを見守ってください\nできることなら、ずっと…", "チカ", 104201, 2, 0, 73, "", 1, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お兄ちゃんと出会って1年かぁ\n私、相変わらずダメダメで…", "クルミ", 102101, 1, 0, 74, "", 2, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("で、でもこれからもずっと…\n一緒にいたいなぁ…", "クルミ", 102101, 2, 0, 75, "", 2, 0, 0, 80001, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("再会してちょうど1年だね\nお祝いにごちそう作ってきたよ～♪\n特製ケーキと、お寿司と、", "シズル", 104901, 1, 0, 76, "", 0, 0, 0, 80001, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ハンバーグと、カレーと、\nシチューと、あ、隠しきれない隠し\n味は、お姉ちゃんの愛情だよ！", "シズル", 104901, 2, 0, 77, "", 0, 0, 0, 80001, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お兄ちゃんと再会して、もう1年\nなんですね。\n会えなかった時を思うと、", "リノ", 101101, 1, 0, 78, "", 1, 0, 0, 80001, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("信じられないくらい幸せな1年\nでした！もう絶対、私から離れ\nないでくださいね♪", "リノ", 101101, 2, 0, 79, "", 1, 0, 0, 80001, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("騎士クンと出会ってから今まで、\nいろんなことがあったよね\n楽しいこと、ドキドキしたこと…", "ユイ", 100201, 1, 0, 80, "", 0, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そんな日々をこれからも、\nず、ずっと一緒に…\n過ごしていきたいな…！", "ユイ", 100201, 2, 0, 81, "", 0, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("騎士くんと出会って、まだ1年しか\nたってないんだ！？", "ヒヨリ", 100101, 1, 0, 82, "", 1, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なんかもうずっと一緒にいる気が\nするなぁ…えへへ。これからの\n1年もまたよろしくねっ！\n騎士くん！", "ヒヨリ", 100101, 2, 0, 83, "", 1, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("初めてキミに出会って1年…\n随分見違えたね私もキミも、\n更に強くなっていく…", "レイ", 100301, 1, 0, 84, "", 2, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キミに背中を預けられる日が、\n早くきますように", "レイ", 100301, 2, 0, 85, "", 2, 0, 0, 80001, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("1年もわたしのことを、忘れない\nでいてくれて、ありがとうござい\nます！", "ペコリーヌ", 105801, 1, 0, 86, "", 0, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからもずっと、覚えていて\nくださいね！", "ペコリーヌ", 105801, 2, 0, 87, "", 0, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("こうして1年も、主さまのおそばに\n置いていただけて、とても光栄\nです。どうかこれからも、", "コッコロ", 105901, 1, 0, 88, "", 1, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("末永く主さまをお世話させて\nください。わたくしは、ずっと\n主さまのガイド役でいたいのです", "コッコロ", 105901, 2, 0, 89, "", 1, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("1年か、まっさかこんなに長い\n付き合いになるなんてね～\nでも…わりと楽しい1年だったかも", "キャル", 106001, 1, 0, 90, "", 2, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("だから、もうしばらくあんたに\n付き合ってやるわよ喜びなさい！", "キャル", 106001, 2, 0, 91, "", 2, 0, 0, 80001, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新しい年のはじめに、\nおみくじはいかがでしょうか？\nよい運勢であるほど、\n沢山プレゼントが貰えますよ♪", "スズメ", 112101, 1, 0, 92, "", 1, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　あらゆる運気が最大を示しています！　　　今なら「伝説の吸血鬼」をも従え、世界征服も夢じゃありません！", "", 0, 0, 1, 93, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 94, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", "", 0, 0, 1, 95, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", "", 0, 0, 1, 96, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　その高い運気はまさにショーグンの如く！　その溢れる威光は人々を惹きつけ、皆の人気者間違いなしです！", "", 0, 0, 1, 97, "", 2, 0, 2, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運気がどんどん高まっています！　　　　　何をやっても、最大効率で素晴らしい結果になりますよ♪", "", 0, 0, 2, 98, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　なにをやっても上手くいって大活躍！　　　そんな素敵なあなたを見て、後ろから誰かが……クスクス♪", "", 0, 0, 2, 99, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", "", 0, 0, 2, 100, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", "", 0, 0, 2, 101, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運気が高く、何かに挑戦すると良い結果に！隠れた才能が引き出されそう！　目指せヒデサ……ではなく秀才！", "", 0, 0, 2, 102, "", 2, 0, 2, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたいやき！　和菓子パワーで売上アップです！", "", 0, 0, 3, 103, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　旅行運がぐんぐんと上昇中♪　　　　　　　もしかしたら、あの「マホマホ王国」にだって行けるかも♪", "", 0, 0, 3, 104, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", "", 0, 0, 3, 105, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", "", 0, 0, 3, 106, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　お出かけした先で良縁に恵まれそうです！　ダウナー系あざとい女子が、あま～い飴をくれるかも？", "", 0, 0, 3, 107, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", "", 0, 0, 3, 108, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかの如く、色々な事がうまくいきますよ♪", "", 0, 0, 3, 109, "", 2, 0, 2, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　早朝に幸運の兆しあり！　　　　　　　　　もしかしたら、優しいお姉ちゃんが起こしにきてくれますよ♪", "", 0, 0, 4, 110, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　運気上昇中ですが、上がるまでが要注意！　ラッキーアニマルは熊！　本当の家族のように守ってくれるかも♪", "", 0, 0, 4, 111, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　外に出てゆっくり過ごすと運気が上昇！　　ラッキースポットは牧場。面白い出会いがありそうです♪", "", 0, 0, 4, 112, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", "", 0, 0, 4, 113, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", "", 0, 0, 4, 114, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　思わぬ相手と仲良くなれるかも？　　　　　うっかり毒舌をもらしてしまわないように要注意です！", "", 0, 0, 4, 115, "", 2, 0, 1, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", "", 0, 0, 4, 116, "", 2, 0, 2, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はいかがでしたか？\n新たに始まる一日が、\nあなたにとってよい日になりますように\n明日もお待ちしていますね♪", "スズメ", 112101, 2, 0, 117, "", 3, 0, 0, 60001, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじ、楽しんで頂けましたか？\nあなたの新しい年が\n素晴らしいものになるよう、\n心からお祈りしますね", "スズメ", 112101, 3, 0, 118, "", 3, 0, 0, 60001, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ヒューヒュー♪\nドンドンパフパフー♪", "ペコリーヌ", 105801, 1, 0, 119, "", 0, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ひゅーひゅー\nどんどんぱふぱふー\nでございます", "コッコロ", 105901, 1, 0, 120, "", 1, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さぁ、キャルさまもご一緒に\nどんどんぱふぱふいたしましょう", "コッコロ", 105901, 2, 0, 121, "", 1, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("え？　ちょっと\nいきなりなにっ？", "キャル", 106001, 1, 0, 122, "", 2, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ドンドンパフパフってなんなの？\nあたしにも分かるように\nちゃんと説明しなさいっての！", "キャル", 106001, 2, 0, 123, "", 2, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("実はですねキャルちゃん！\nもうすぐわたしたちにとっての\n大切な節目──", "ペコリーヌ", 105801, 2, 0, 124, "", 0, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("『プリンセスコネクト！\nRe:Dive』\n2.5周年なんですよ！\nやばいですね☆", "ペコリーヌ", 105801, 3, 0, 125, "", 0, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですからその日に向けて\n今から気分を盛り上げているのです", "コッコロ", 105901, 3, 0, 126, "", 1, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ああ、そういえば\nそんな時期だっけ\nって言っても、もう少し先じゃない\n気が早いんじゃないの？", "キャル", 106001, 3, 0, 127, "", 2, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いいえ、キャルさま\nこういったお祝いは準備から\n楽しむものでございます\nそうですよね、ペコリーヌさま", "コッコロ", 105901, 4, 0, 128, "", 1, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("その通りです♪　というわけで！\nカウントダウンの始まりですよ！\nみんなで一緒に2.5周年に向けて\n盛り上がっていきましょー☆", "ペコリーヌ", 105801, 4, 0, 129, "", 0, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ド、ドンドンパフパフ～\nって何言わせんのよ！\nまったくもう、浮かれちゃってさ", "キャル", 106001, 4, 0, 130, "", 2, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ。キャルさまもワクワクして\nおいでのようですね\nそれでは主さま。大切な記念日まで\nどうぞご期待くださいませ", "コッコロ", 105901, 5, 0, 131, "", 1, 0, 0, 80003, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("記念日を盛り上げるったって\n一体どうしたらいいのよ？\nあたし、そういうの\n苦手なんだけど…", "キャル", 106001, 5, 0, 132, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あら、キャルさん\nどうかなさいましたか？\n何かお困りのようですけど", "カリン", 190801, 1, 0, 133, "", 1, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("げっ…カリンじゃない\nなんでもないわよ！", "キャル", 106001, 6, 0, 134, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そうなのですか？\nキャルさんのことですからてっきり\n2.5周年をどう盛り上げたら\nいいか悩んでいるのかと…", "カリン", 190801, 2, 0, 135, "", 1, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("分かってんじゃないのよ！？\nいっ、いや、違うけどね！\nあたしは別にそんなことで\n悩んでないわよっ？", "キャル", 106001, 7, 0, 136, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふっ…\nこういう時は、真心を込めて\n気持ちをそのまま口にしたら\nいいのではないでしょうか？", "カリン", 190801, 3, 0, 137, "", 1, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("気持ちを、ねぇ\nそれが一番難しいんじゃない…\nそもそも、あたしは記念日とか\n別にどうだっていいし", "キャル", 106001, 8, 0, 138, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…まあ、ペコリーヌもコロ助も\nやけに楽しそうだったから…\nこういうお祭り騒ぎみたいなのも\nたまにはいいかな、とは思うけど", "キャル", 106001, 9, 0, 139, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なるほどなるほど～\nキャルさんは【美食殿】で祝う\n2.5周年を心から楽しみに\nしている、ということですね！", "カリン", 190801, 4, 0, 140, "", 1, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はぁ！？\nどこ聞いたらそうなるのよ！\nあたしは別に楽しみになんか…！", "キャル", 106001, 10, 0, 141, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルさんの心からの想い\nみなさんにも伝わったでしょうか？\n私も2.5周年が楽しみです！\n以上、カリンがお伝えしました！", "カリン", 190801, 5, 0, 142, "", 1, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("心からの想いって何なのよ！？\n勝手に人の言葉を\n捻じ曲げんじゃないわよ！\nこのくそ眼鏡ーーーっ！", "キャル", 106001, 11, 0, 143, "", 0, 0, 0, 80003, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ペコリーヌさま、もうすぐ\n記念日でございますね\nこういった節目というのは\n感慨深いものでございます", "コッコロ", 105901, 6, 0, 144, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("色んな思い出が蘇ってきますね！\n楽しい出来事が\nいっぱいありました♪", "ペコリーヌ", 105801, 5, 0, 145, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい、そうでございますね\n主さまも【美食殿】の活動の他にも\nいろんなご経験をされたと\n聞いておりますよ", "コッコロ", 105901, 7, 0, 146, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("たしか…ランドソルで話題沸騰と\nなっていた、魔法少女なるものに\nお会いになられたとか", "コッコロ", 105901, 8, 0, 147, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("魔法少女って、あの美味しくって\n栄養たっぷりの大ヒット商品\n『魔法少女ソーセージ』の箱に\n描いてある女の子のことですか！？", "ペコリーヌ", 105801, 6, 0, 148, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あのソーセージ\n美味しいんですよね～♪\nわたしもたっくさん食べてますよ！", "ペコリーヌ", 105801, 7, 0, 149, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あとは、牧場に素敵な温泉が\n出来たとか…", "コッコロ", 105901, 9, 0, 150, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("牧場ですか！？　温泉につかって\nチーズもオツですね～♪　考えた\nだけでよだれが出ちゃいそうです！\nやばいですね☆", "ペコリーヌ", 105801, 8, 0, 151, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ペコリーヌさま\n言ってるそばからよだれが…\n今お拭きしますね。ふき、ふき", "コッコロ", 105901, 10, 0, 152, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えへへ、ありがとうございます\nコッコロちゃん！", "ペコリーヌ", 105801, 9, 0, 153, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それにしても、主さまは\n【美食殿】の一員として様々な\n美食と出会われていたのですね\nわたくし、感服いたしました", "コッコロ", 105901, 11, 0, 154, "", 0, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからもたくさん冒険をして\nめいっぱい美食を\n味わい尽くしましょうね！", "ペコリーヌ", 105801, 10, 0, 155, "", 1, 0, 0, 80003, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年カウントダウン♪\nキャルちゃんキャルちゃん！\nわくわくしますね☆", "ペコリーヌ", 105801, 11, 0, 156, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あぁもう、うるさいわね～\nまだまだ先でしょ？\nちょっとは落ち着きなさいよ", "キャル", 106001, 12, 0, 157, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルちゃんだって最近\nソワソワしてるじゃないですか～\nさっきもご機嫌そうに鼻歌とか\n歌ってましたよね？", "ペコリーヌ", 105801, 12, 0, 158, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なっ…！　き、聞いてたの！？\nじゃない、歌ってないわよ！？\nあんたいい加減なこと言うと\nぶっ殺すわよ！？", "キャル", 106001, 13, 0, 159, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっへへ～♪\nわたしは最近のキャルちゃんが\nもっともっと大好きですよ♪\nすごく積極的になりましたよね！", "ペコリーヌ", 105801, 13, 0, 160, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…積極的？\nなんの話よ？", "キャル", 106001, 14, 0, 161, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("またまた～♪\nアイドルを目指そうとしたこと\n忘れちゃったんですか？", "ペコリーヌ", 105801, 14, 0, 162, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ムーサの町で\nきゃるきゃる～ん☆　って！", "ペコリーヌ", 105801, 15, 0, 163, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あっ…！？　ちちち違うわよっ！\nあれは操られてただけで\nあたしはアイドルなんか\n目指してないっての！！", "キャル", 106001, 15, 0, 164, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("本当に本当ですか？\nわたし、キャルちゃんとっても\n乗り気だなって\n思ってたんですけど～", "ペコリーヌ", 105801, 16, 0, 165, "", 0, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("まぁ、悪くはなかったけど…って\nだ、だから目指してないって\n言ってるでしょ！！\nなんてこと思い出させんのよ！？", "キャル", 106001, 16, 0, 166, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ああ…ダメだわ…\nもう殺すしかない…\n2.5周年が来る前に\n記憶ごと消し去ってやるー！", "キャル", 106001, 17, 0, 167, "", 1, 0, 0, 80003, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年まであと10日…\nふ～ん？\n案外早いもんね？", "キャル", 106001, 18, 0, 168, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そうでございますね…\nその日のためにやるべきことは\nまだまだございます\n気を引き締めねばなりません…！", "コッコロ", 105901, 12, 0, 169, "", 1, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("やる気十分ねコロ助…\nそんな気負ってるとしんどいわよ？\nお気楽にやりましょ？", "キャル", 106001, 19, 0, 170, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルさま…\nありがとうございます\nキャルさまは本当に\n優しいおかたです", "コッコロ", 105901, 13, 0, 171, "", 1, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("な、なにわけの分かんないこと\n言ってんのよ…\nあたしは優しくなんかないっての", "キャル", 106001, 20, 0, 172, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そんなことはございません\n…あの、実はわたくし\nキャルさまに\nひとつお願いがございまして", "コッコロ", 105901, 14, 0, 173, "", 1, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お願い？　珍しいわね\nコロ助がそんなこと言うなんて\n…まあ、あたしに出来ることなら\n別にいいけど", "キャル", 106001, 21, 0, 174, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ありがとうございます\n実は記念日へ向けて\n『かくし芸』というものを\n用意してみようかと思いまして", "コッコロ", 105901, 15, 0, 175, "", 1, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("かくし芸？", "キャル", 106001, 22, 0, 176, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい。きゃるきゃる～ん☆　を\n参考に、ころころ～ん☆　という\nご挨拶を考えてみたのですが\nポーズがうまくいかなくて…", "コッコロ", 105901, 16, 0, 177, "", 1, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("～～！！　ちょっと褒められて\nいい気になって損したわ！！\nふざけんなふざけんな\nふ～ざ～け～ん～な～っ！！", "キャル", 106001, 23, 0, 178, "", 0, 0, 0, 80003, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あと９日！　もうすぐですよ♪\nえへへ、楽しみで楽しみで\nごはんが進みますね☆", "ペコリーヌ", 105801, 17, 0, 179, "", 0, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ごはんが進みますね☆\nじゃなーい！\nいくらなんでも食べ過ぎよ！\n記念日、迎えられなくなるわよ！？", "キャル", 106001, 24, 0, 180, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("大丈夫ですよキャルさま\n食事はわたくしたちの\n歩んできた道そのもの\nなのですから", "コッコロ", 105901, 17, 0, 181, "", 1, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さっすがコッコロちゃん\nいいことを言いますね！\nそう、わたしたち\n【美食殿】の活動目的は─", "ペコリーヌ", 105801, 18, 0, 182, "", 0, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("─みんなで楽しく食事をすること\nでしょ？\nあれだけ食べ歩いてきたんだから\n分かってるわよ", "キャル", 106001, 25, 0, 183, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい…そうでございますね♪\nそれにしてもわたくしたち\n本当にいろいろなものを\n食べ歩いてきましたね…", "コッコロ", 105901, 18, 0, 184, "", 1, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そうね…ほんっとうにね…\n毒まみれのニセドラゴンとか\n恐竜…は逃げられちゃったっけ\nあとワニゴ…ワニの魔物とかね", "キャル", 106001, 26, 0, 185, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そして、とうとう本物の\nドラゴンまで相手に\nしちゃったのよね、あたしたちって", "キャル", 106001, 27, 0, 186, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("信じられない強さだったわね\nあのドラゴン…やっぱり\n作戦はしっかり立てていかないと\nダメよね", "キャル", 106001, 28, 0, 187, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えへへ…☆\nキャルちゃんが色んなことを\n覚えていてくれて\nうれしいです♪", "ペコリーヌ", 105801, 19, 0, 188, "", 0, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わたくしも鮮明に覚えておりますよ\n主さまもきっと…♪", "コッコロ", 105901, 19, 0, 189, "", 1, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あったり前でしょ！\n忘れないわよ、あんな滅茶苦茶な\nものばかり食べさせられて！\n…忘れられるわけ、ないじゃない", "キャル", 106001, 29, 0, 190, "", 2, 0, 0, 80003, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ねえちょっと、ちょっと待って！？\nカリンから、2.5周年記念の\n生放送に出演してほしいって\n言われたんだけど！", "キャル", 106001, 30, 0, 191, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なんでそういう大事なことを\n急に言うわけ！？\nそんなの聞いてないわよ～！？", "キャル", 106001, 31, 0, 192, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いっぱい人に見られちゃうのよね？\nなんであたしがそんなこと…", "キャル", 106001, 32, 0, 193, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あー\nあー\n…声、これで大丈夫かしら？", "キャル", 106001, 33, 0, 194, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("聞き取りにくいかもしれないわね…\nもうちょっと明るい方がいいかも\nえっと…こんな感じ？", "キャル", 106001, 34, 0, 195, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆", "キャル", 106001, 35, 0, 196, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("……\nいや、ないわ\nいつもどおりが一番ね、うん", "キャル", 106001, 36, 0, 197, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もう、記念の生放送なんて\n超責任重大なやつじゃない…\nもしなにか失敗とかしたら…", "キャル", 106001, 37, 0, 198, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ど、どど、どうしよう！？\n緊張してきちゃった…！！", "キャル", 106001, 38, 0, 199, "", 0, 0, 0, 80003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("主さま、わたくし\nペコリーヌさまとキャルさまと共に\n2.5周年を祝う生放送に\n出演する大役を仰せつかりました", "コッコロ", 105901, 20, 0, 200, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("多くの方々に\n『プリンセスコネクト！\nRe:Dive』の魅力をお伝えする\n重要な役割でございます", "コッコロ", 105901, 21, 0, 201, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わたくし、全身全霊をもって\n生放送に取り組みたいと\n思っております", "コッコロ", 105901, 22, 0, 202, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですが、もしかしたら\nセリフを噛んでしまったり\n段取りを間違えてしまったり\nするかもしれません…", "コッコロ", 105901, 23, 0, 203, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そのようなことがないよう\n練習はしっかりしておかなくては\nまずはこちらから…", "コッコロ", 105901, 24, 0, 204, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆", "コッコロ", 105901, 25, 0, 205, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("先ほどキャルさまが練習されて\nいるのをお見かけしたので\nわたくしもと思いまして…\nいかがでしょうか？", "コッコロ", 105901, 26, 0, 206, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("良い感じ、ですか？\n…ふふ、ありがとうございます\n主さまのあたたかいお言葉があれば\nわたくしは百人力でございます", "コッコロ", 105901, 27, 0, 207, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("この大役を無事に成し遂げ\n主さまに素敵な2.5周年を\n迎えていただけるよう…\nわたくし、尽力いたしますね", "コッコロ", 105901, 28, 0, 208, "", 0, 0, 0, 80003, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆", "ペコリーヌ", 105801, 20, 0, 209, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…う～ん、今のはちょっと\n違う感じがしますね\n堅苦しかったかもしれません", "ペコリーヌ", 105801, 21, 0, 210, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あと６日で2.5周年ですか…", "ペコリーヌ", 105801, 22, 0, 211, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("この年月がオイッスーの\n歴史なんだと思うと\nじ～んとしちゃいます！\nやばいですね☆", "ペコリーヌ", 105801, 23, 0, 212, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("生放送で最高のオイッスー☆　を\nみなさんにお届けするために\n頑張らないと！\nそれじゃあもう一度…", "ペコリーヌ", 105801, 24, 0, 213, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆", "ペコリーヌ", 105801, 25, 0, 214, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…うう～ん、どうしてでしょう\nまだ何かが違う気がします…\nもしかしたら\nおなかが空きすぎてるとか？", "ペコリーヌ", 105801, 26, 0, 215, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今さっき食べたばっかりですけど\nおなかが減っては\n良いオイッスー☆　は\n出せませんよね！", "ペコリーヌ", 105801, 27, 0, 216, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そうと決まれば、コッコロちゃんと\nキャルちゃんを誘って\nごはんにしましょう！\n善は急げです！", "ペコリーヌ", 105801, 28, 0, 217, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あ、二人が丁度いいところに！\nオイッス～☆　…ああ！！\n今の、今のですよ～♪", "ペコリーヌ", 105801, 29, 0, 218, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なるほど、どんな時も\n自然体が一番ってことですね！\nこの調子で、生放送も\n頑張っちゃいます♪", "ペコリーヌ", 105801, 30, 0, 219, "", 0, 0, 0, 80003, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年まで残り５日ですが\nその前にもうすぐ生放送ですよ！\nコッコロちゃん\n準備の方はどうですか？", "ペコリーヌ", 105801, 31, 0, 220, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい。わたくし、しっかりと\n備えてまいりました\n万事抜かりはございません", "コッコロ", 105901, 29, 0, 221, "", 1, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おお～すごい自信を感じます…！\nいい生放送になりそうですね☆\n……あれ？　なんだかこの辺り\n揺れていませんか？", "ペコリーヌ", 105801, 32, 0, 222, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…………", "キャル", 106001, 39, 0, 223, "", 2, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルさま？\nお風邪をひかれたんでしょうか\nひどい震えですが…", "コッコロ", 105901, 30, 0, 224, "", 1, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("かかかか風邪じゃないわよ！\nここここれはただ\nななな生放送が楽しみ過ぎて\nワワワワクワクが止まらないだけ！", "キャル", 106001, 40, 0, 225, "", 2, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("大丈夫ですかキャルちゃん！？\nそうだ、これを飲んでください！", "ペコリーヌ", 105801, 33, 0, 226, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("きき気がきくじゃない、ありがとっ\nごくっ、んく…ぶはぁっ！？\nちょっと何飲ませたの！？\n辛っ！　苦ぁ！？　甘ぁっ！？", "キャル", 106001, 41, 0, 227, "", 2, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これは魔物のエキスに薬草に\nその他色んなものを混ぜた\n特製の栄養ドリンクです！", "ペコリーヌ", 105801, 34, 0, 228, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これを飲めば体ぽかぽかで\n元気いっぱいですよ♪", "ペコリーヌ", 105801, 35, 0, 229, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("このアホリーヌ！\n風邪じゃないって言ったでしょ！？\nどさくさに紛れて\nそんな恐ろしいもん飲ませんな～！", "キャル", 106001, 42, 0, 230, "", 2, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルさま\n震えが収まっておりますね\nよかったです…\nわたくし、心配いたしました", "コッコロ", 105901, 31, 0, 231, "", 1, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("え？　ああ、ホントね…って\nだから風邪じゃないって\n言ってるのに…\nまあいいわこの際なんでも", "キャル", 106001, 43, 0, 232, "", 2, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっへへ～♪　いつも通りの\nキャルちゃんに戻りましたし\n素敵な生放送が出来そうですね！\n今から楽しみです☆", "ペコリーヌ", 105801, 36, 0, 233, "", 0, 0, 0, 80003, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ランドソルのみなさま、こんにちは\n生放送の会場設営を担当しています\n【ギルド管理協会】のカリンです", "カリン", 190801, 6, 0, 234, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("【美食殿】のみなさんは\nまもなく始まる生放送に向けて\n最後の調整のため\n席を外しています", "カリン", 190801, 7, 0, 235, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("頑張っている３人の\n邪魔をするわけには\nいきませんので、ご容赦ください", "カリン", 190801, 8, 0, 236, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですので、本日は私から\n【美食殿】のみなさんの様子を\nお伝えさせていただこうと思います", "カリン", 190801, 9, 0, 237, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("まずはペコリーヌさんですが…\n何やら大量のおにぎりを\n食べているようです\nえっと…栄養は大事ですよね", "カリン", 190801, 10, 0, 238, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("次にコッコロさんですが\nこちらは発声練習をしています", "カリン", 190801, 11, 0, 239, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("一生懸命、小さなお口を開けて\n声を出す姿が応援したくなりますね", "カリン", 190801, 12, 0, 240, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そしてキャルさんは…\nこれは…堂々としたものですね\n何もせず、ただ立ち尽くして…", "カリン", 190801, 13, 0, 241, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あれ？\nもしかして緊張で気を失って…？", "カリン", 190801, 14, 0, 242, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…ええと\n【美食殿】のみなさんは\nやる気十分なようですね！", "カリン", 190801, 15, 0, 243, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("３人とも生放送を\nいいものにしようと\n全力で頑張ってくれていますので\nどうかご期待ください", "カリン", 190801, 16, 0, 244, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それでは\nまた明日お会いしましょう♪", "カリン", 190801, 17, 0, 245, "", 0, 0, 0, 80003, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年まであと３日！\nそして生放送は明日！\nなんかいよいよって感じね…", "キャル", 106001, 44, 0, 246, "", 0, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("３人でい～っぱい練習しましたし\nきっと大丈夫ですよ☆", "ペコリーヌ", 105801, 37, 0, 247, "", 2, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ペコリーヌさまに\n大丈夫と言ってもらえると\nとても心強いですね", "コッコロ", 105901, 32, 0, 248, "", 1, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("信じすぎちゃだめよコロ助\nこいつはなーんにも\n考えてないだけなんだから", "キャル", 106001, 45, 0, 249, "", 0, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ひどいですよぉキャルちゃ～ん！", "ペコリーヌ", 105801, 38, 0, 250, "", 2, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ。お二人とも\n普段通りの様子で\n安心いたしました", "コッコロ", 105901, 33, 0, 251, "", 1, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はいっ☆\n生放送でもなんでも\n全力全開、わたしらしく\nぶつかっていくだけです！", "ペコリーヌ", 105801, 39, 0, 252, "", 2, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そうね。おめでたいことなんだし\nここまで来たんなら\n楽しめるだけ\n楽しむしかないわよね！", "キャル", 106001, 46, 0, 253, "", 0, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わたくしも、普段よりも心が\n熱くなっております\nこの胸の気持ちをお伝えできるよう\n精一杯努力いたします…！", "コッコロ", 105901, 34, 0, 254, "", 1, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それでは、いきましょう！\n明日の生放送、絶対に\n成功させましょうね☆", "ペコリーヌ", 105801, 40, 0, 255, "", 2, 0, 0, 80003, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっと、最初のひと言は…あれ？\nキャルちゃん、わたし\n何て言うんでしたっけ？", "ペコリーヌ", 105801, 41, 0, 256, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("は！？\nなにいきなりど忘れしてるの！？\nっていうかあんた、台本は！？", "キャル", 106001, 47, 0, 257, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("忘れてきちゃいました☆", "ペコリーヌ", 105801, 42, 0, 258, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("忘れてきちゃいました☆\nで済ませられると思ってんの！？\nほら、あたし二冊持ってきたから\nこれ使いなさい！", "キャル", 106001, 48, 0, 259, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("マイクとは、こんな高い位置に\nあるものなのですね…！\n背伸びをすれば、何とか…\nう～ん、うぅ～ん…！", "コッコロ", 105901, 35, 0, 260, "", 1, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あぁもう\n少し下げればいいでしょ！？\nこれくらいでいい？\nまったく、世話が焼けるわね…", "キャル", 106001, 49, 0, 261, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あれ？\nキャルちゃん、後ろ髪が\nはねちゃってますよ？", "ペコリーヌ", 105801, 43, 0, 262, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("え？　うそっ！？\nちゃんと確かめてきたのに！\nどこどこ！？", "キャル", 106001, 50, 0, 263, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルさま、動かないで\nくださいまし。今くしで…\nはい、直りましたよ", "コッコロ", 105901, 36, 0, 264, "", 1, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あ、ありがと…はぁ。生放送\n本番までもうすぐなのに\nこんなことしてる場合じゃ\nないわよね", "キャル", 106001, 51, 0, 265, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい、時間は残りわずかです\nですが、慌ただしく\n動き回るこの時間も\nなんだか楽しくて…♪", "コッコロ", 105901, 37, 0, 266, "", 1, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("コロ助、あんた…って\nそうじゃなくて！\n胸にジンワリきてる\n暇なんかないでしょ…！？", "キャル", 106001, 52, 0, 267, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あはは♪\nキャルちゃんの動きが\nとっても面白いです♪\nやばいですね☆", "ペコリーヌ", 105801, 44, 0, 268, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ\nきっと面白い生放送になると\nわたくし、確信しております", "コッコロ", 105901, 38, 0, 269, "", 1, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("絶対絶対、間違いありません！\n見てくれるみなさんが\n笑顔になれる時間を\nお届けしましょう！", "ペコリーヌ", 105801, 45, 0, 270, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そんなの当然でしょ！\n誰が見たって面白いって\n言ってもらえるように\nあれだけ準備したんだから！", "キャル", 106001, 53, 0, 271, "", 2, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それでは\n記念日直前生放送！\n楽しみにしててくださいね☆", "ペコリーヌ", 105801, 46, 0, 272, "", 0, 0, 0, 80003, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("こんにちは\n【ギルド管理協会】のカリンです", "カリン", 190801, 18, 0, 273, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("昨日の生放送は\nいかがだったでしょうか？", "カリン", 190801, 19, 0, 274, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("たくさんの笑顔と喜びと\nそして驚きを受け取って\nいただけたのではないかと思います", "カリン", 190801, 20, 0, 275, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そしていよいよ\n明日は2.5周年の当日\n待ちに待った記念日を\n迎えることとなります", "カリン", 190801, 21, 0, 276, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("【美食殿】のみなさんも\n張り切って様々な準備を\nされていますよ", "カリン", 190801, 22, 0, 277, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("【ギルド管理協会】も\n万全のサポート体制で\n協力してまいりたいと思います", "カリン", 190801, 23, 0, 278, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…ふふ、本当に楽しみですね\n【ギルド管理協会】の職員として\nだけではなく、私個人としても…", "カリン", 190801, 24, 0, 279, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("この記念日を迎えられることが\n心から楽しみですし\n幸せを感じています", "カリン", 190801, 25, 0, 280, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("きっと【美食殿】のみなさんは\nそれ以上に心を弾ませて\nいることでしょう", "カリン", 190801, 26, 0, 281, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それでは\n明日からの2.5周年を\nどうぞ、お楽しみに…♪", "カリン", 190801, 27, 0, 282, "", 0, 0, 0, 80003, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("準備はいいですかっ？\n…いっきますよー！", "ペコリーヌ", 105801, 47, 0, 283, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("祝！", "キャル", 106001, 54, 0, 284, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年！", "コッコロ", 105901, 39, 0, 285, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おめでとうございま～す☆", "ペコリーヌ", 105801, 48, 0, 286, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("少し前まではまだまだ先じゃない\nとか言ってたけど\n本当にあっという間だったわね", "キャル", 106001, 55, 0, 287, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("光陰矢の如し…\nとはこのことでございますね\nでも、今日という日を無事に\n迎えることができて良かったです", "コッコロ", 105901, 40, 0, 288, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("コッコロちゃん！　キャルちゃん！\n落ち着くには\nまだ早いですよ！\n盛り上がるのはこれからです☆", "ペコリーヌ", 105801, 49, 0, 289, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ほんとあんたはいつも\n全力全開ねー\nでもそうね、記念日なんだし\nパーっといきましょ！", "キャル", 106001, 56, 0, 290, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええ、わたくしも全力全開で\nまいります…！\n主さま、さあ\nどうぞ手を取ってくださいまし…♪", "コッコロ", 105901, 41, 0, 291, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あんたもコロ助も、浮かれて\n転ぶんじゃないわよ？\n…仕方ないから、あたしも\n手を繋いであげるわよ", "キャル", 106001, 57, 0, 292, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あー！　二人ともずるいです！\nわたしもっ、ギュー♪", "ペコリーヌ", 105801, 50, 0, 293, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ちょっ、ペコリーヌ！\nくっつき過ぎよ！", "キャル", 106001, 58, 0, 294, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("記念日だから\n平気平気♪\nやばいですね☆", "ペコリーヌ", 105801, 51, 0, 295, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("意味分かんないわよ！", "キャル", 106001, 59, 0, 296, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ。このめでたき日に\n喜びがあふれておりますね\n主さまは…いかがでしょうか？", "コッコロ", 105901, 42, 0, 297, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("喜んでいただけているならば\nわたくしはとてもとても\n幸せでございます", "コッコロ", 105901, 43, 0, 298, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さぁ、2.5周年を\n楽しみ尽くしますよ☆\nまだまだ食べたいものもありますし\nやりたいこともたくさんです！", "ペコリーヌ", 105801, 52, 0, 299, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("分かった、分かったから\n引っ張るんじゃないわよ！\n…そんな掴まなくても\nちゃんとついていくから", "キャル", 106001, 60, 0, 300, "", 2, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ペコリーヌさま…キャルさま…\n主さま…共にまいりましょう\nどこまでも…！", "コッコロ", 105901, 44, 0, 301, "", 1, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい！　それでは2.5周年\n食べつくしツアーへ！\nそして、その先の未来へ\n向かって出発しましょう！", "ペコリーヌ", 105801, 53, 0, 302, "", 0, 0, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("2.5周年\nありがとうございます！", "ペコリーヌ・コッコロ・キャル", 105801, 54, 0, 303, "105901,45,106001,61", 0, 1, 0, 80003, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", "カリン", 190804, 1, 0, 304, "", 1, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", "", 0, 0, 1, 305, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 306, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　最強の運勢でどんなドジも跳ね除けます！　大切な人と一緒に、最高の一日になること間違いなし！", "", 0, 0, 1, 307, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　どんな挑戦も上手くいく、最高の運勢です！理想の自分に変身できる絶好の機会！　新しい一歩を踏み出そう！", "", 0, 0, 1, 308, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", "", 0, 0, 1, 309, "", 2, 0, 2, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", "", 0, 0, 2, 310, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", "", 0, 0, 2, 311, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーワードは「ちぇる～ん♪」　　　　出会う人みんなに言ってあげると、ハッピーになれますよ！", "", 0, 0, 2, 312, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　運勢はバッチリで無敵状態！　　　　　　　龍眼で全てを見通して、思い通りの一日を過ごしましょう！", "", 0, 0, 2, 313, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", "", 0, 0, 2, 314, "", 2, 0, 2, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", "", 0, 0, 3, 315, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", "", 0, 0, 3, 316, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", "", 0, 0, 3, 317, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", "", 0, 0, 3, 318, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　商売運が上がってきています！　　　　　　ラッキーアイテムはたい焼き！　和菓子パワーで売上アップです！", "", 0, 0, 3, 319, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", "", 0, 0, 3, 320, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　運気が着々と上昇中！　　　　　　　　　　精霊の加護を受けたかのごとく、色々な事がうまくいきますよ♪", "", 0, 0, 3, 321, "", 2, 0, 2, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", "", 0, 0, 4, 322, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", "", 0, 0, 4, 323, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", "", 0, 0, 4, 324, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　運気は高いけども、ハプニングには注意！　出かけた先で、「ふしんしゃ」扱いされてしまうかも……", "", 0, 0, 4, 325, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", "", 0, 0, 4, 326, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", "", 0, 0, 4, 327, "", 2, 0, 1, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　根を詰めずにリラックスすると運気向上！　ラッキーパーソンはアイドル。歌があなたを幸せにしてくれます♪", "", 0, 0, 4, 328, "", 2, 0, 2, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", "カリン", 190804, 2, 0, 329, "", 3, 0, 0, 60002, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", "カリン", 190804, 3, 0, 330, "", 3, 0, 0, 60002, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ささ、シェフィさまはこちらへ…", "コッコロ", 105901, 1, 0, 331, "", 4, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("コッコロさん、どこへ行くの…？\n…え？", "シェフィ", 106401, 1, 0, 332, "", 0, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("『おめでとうございます！\nわ～パチパチー！』\n…という感じでどうですかね！？", "ペコリーヌ", 105801, 1, 0, 333, "", 3, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ではわたくしも\n後ろからクラッカーを鳴らして\n応戦いたします\nああ、当日が待ち遠しいですね", "コッコロ", 105901, 2, 0, 334, "", 4, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええと…\n二人とも何をしているの？", "シェフィ", 106401, 2, 0, 335, "", 0, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("シェフィは初めてだもんね\nあの日が近いからって\n予行練習してんのよ\n気が早いわよね～", "キャル", 106001, 1, 0, 336, "", 1, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あの日…？", "シェフィ", 106401, 3, 0, 337, "", 0, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("その通りです…\nいよいよ記念すべきあの日が\n近づいてきましたよ！", "ペコリーヌ", 105801, 2, 0, 338, "", 3, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("『プリンセスコネクト！\nRe:Dive』3.5周年！", "ペコリーヌ", 105801, 3, 0, 339, "", 3, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("やばいですね☆", "カリン", 190801, 1, 0, 340, "", 2, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("って、なにしれっと\n参加してんのよカリン！", "キャル", 106001, 2, 0, 341, "", 1, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ、いいじゃないですか\n【ギルド管理協会】として\n私もみなさんと一緒に\nお祝いをさせてください！", "カリン", 190801, 2, 0, 342, "", 2, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それに…記念日が近づけば\nとっておきの情報を\nお届けしますから♪", "カリン", 190801, 3, 0, 343, "", 2, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("というわけで\n今日からシェフィちゃんも一緒に\nカウントダウンしちゃいましょう！\n3.5周年まで…", "ペコリーヌ", 105801, 4, 0, 344, "", 3, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっ！？　ええとええと…！\nあ、あと14日…！", "シェフィ", 106401, 4, 0, 345, "", 0, 0, 0, 80005, 1);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと13日\n豪華に、そして盛大に\nお祝いしたいですね☆", "ペコリーヌ", 105801, 5, 0, 346, "", 3, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("豪華といえば前にとある貴族さまが\n舞踏会を開かれたそうで\n主さまがそのお手伝いを\nしておりました", "コッコロ", 105901, 3, 0, 347, "", 1, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そこで美しい所作を学ばれたので\nわたくしも教えていただきました\nしゃなり、しゃなり…\nいかがでしょう？", "コッコロ", 105901, 4, 0, 348, "", 1, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("すっごく上手ですよ☆\nまるでお姫様みたいです\nせっかくなのでわたしも\nしゃなりしゃなり", "ペコリーヌ", 105801, 6, 0, 349, "", 3, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さすがでございます\nペコリーヌさま", "コッコロ", 105901, 5, 0, 350, "", 1, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いや、あんたは\nできなきゃダメでしょ\n本物のお姫様なんだし", "キャル", 106001, 3, 0, 351, "", 0, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("しゃなり、しゃなり…\nふふ、案外できるものね", "シェフィ", 106401, 5, 0, 352, "", 2, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わぁ！\nシェフィちゃん\n姿勢がとってもキレイです♪", "ペコリーヌ", 105801, 7, 0, 353, "", 3, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さ、次はキャルさまの\n番でございますよ", "コッコロ", 105901, 6, 0, 354, "", 1, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あ、あたしはいいわよ！\nそういうの全然分かんないし…", "キャル", 106001, 4, 0, 355, "", 0, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("大丈夫\nやってみると結構楽しいわよ\nほらほらっ", "シェフィ", 106401, 6, 0, 356, "", 2, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そ、そこまで言うなら…\nしゃなにゅわきゃあっ！", "キャル", 106001, 5, 0, 357, "", 0, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いたたた…もぉお～！\nなんであたしがこんな目に～！", "キャル", 106001, 6, 0, 358, "", 0, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("まぁまぁ\n記念日までに練習すれば\nできるようになるかもしれません\nよろしければお教えいたしますよ", "コッコロ", 105901, 7, 0, 359, "", 1, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("よし！\nあんたたちができて\nあたしだけできないのはしゃくだし\nやってやろうじゃないの！！", "キャル", 106001, 7, 0, 360, "", 0, 0, 0, 80005, 2);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと12日\n記念日当日はもちろんですが\nその日を待つ時間というのも\n心躍ります", "コッコロ", 105901, 8, 0, 361, "", 1, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("分かりますっ！\nどんな特別な料理を食べられるのか\n考えるだけでワクワクしますよね！", "ペコリーヌ", 105801, 8, 0, 362, "", 3, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("特別な料理といえば、お祭りですね\nそういえば主さまは学生として\n聖学祭に参加されたこと\nがあるとか…", "コッコロ", 105901, 9, 0, 363, "", 1, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("聖学祭…って、なにかしら？", "シェフィ", 106401, 7, 0, 364, "", 2, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("聖テレサ女学院の祭典ですよ\n二つのチームが競い合い\n青春を満喫するのが趣旨のようです", "コッコロ", 105901, 10, 0, 365, "", 1, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それってカルミナの\nサプライズライブがあった\nお祭りよね？\nちょっと見たかったかも…", "キャル", 106001, 8, 0, 366, "", 0, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("カルミナの後の\nライブも好評だったらしいじゃない\n確か、なかよし部\nだったっけ…？", "キャル", 106001, 9, 0, 367, "", 0, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なかよし部…\n仲が良さそうな名前で\nやばいですね☆", "ペコリーヌ", 105801, 9, 0, 368, "", 3, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いや、そのまんますぎでしょ…", "キャル", 106001, 10, 0, 369, "", 0, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("聖学祭かぁ…なんだか楽しそうね\nそれになかよし部の人たちも\n気になるわ", "シェフィ", 106401, 8, 0, 370, "", 2, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それじゃあわたしたちも、\n負けじと仲良くしましょう♪\nほらほらシェフィちゃん、\nぎゅーっ☆　ですよ♪", "ペコリーヌ", 105801, 10, 0, 371, "", 3, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっ？　ええ…\nぎゅーっ…？", "シェフィ", 106401, 9, 0, 372, "", 2, 0, 0, 80005, 3);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと11日！？\nお祝いの準備進んでないんだけど…\nああ～昨日に戻りたいわ…", "キャル", 106001, 11, 0, 373, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そういえばそんな魔道具があるって\n聞いたことがあるわね\n確か、名前はタイムラーベ…", "シェフィ", 106401, 10, 0, 374, "", 2, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なにそれヤバいわね\nでも本当にあるんだったら\n準備よりももっとやり直したいこと\nたくさんあるんだけど…", "キャル", 106001, 12, 0, 375, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もしや正月の件でしょうか…？\nあの時はお金がなくて\n苦労しましたから", "コッコロ", 105901, 11, 0, 376, "", 1, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あれはそうね…\nお金を湯水のように使う\nぺコリーヌを止められたら\nあんな苦労をすることもなかったし", "キャル", 106001, 13, 0, 377, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そんなこともありましたね！\nやり直したいといえば\n『きゃるきゃる～ん♪』\nの方かと思いましたよ！", "ペコリーヌ", 105801, 11, 0, 378, "", 3, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("バラすんじゃないわよ\nこのアホリーヌ！\nシェフィはそれ\n知らないんだから！", "キャル", 106001, 14, 0, 379, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("こうなったらもう、なんとか\nタイムラーべを探し出して\n今の会話をなかったことに…\nって、どうしたのよシェフィ", "キャル", 106001, 15, 0, 380, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("うん…もし、私だったら…\n私が知らないみんなとの時間を\n見てみたいな、って…", "シェフィ", 106401, 11, 0, 381, "", 2, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("シェフィちゃん！　タイムなんとか\nなんかなくても大丈夫ですよ！\n一緒の時間はこれから\nどんどん作ればいいんですから！", "ペコリーヌ", 105801, 12, 0, 382, "", 3, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい、今この瞬間も\n未来にはかけがえのない思い出に\nなっていることでしょう", "コッコロ", 105901, 12, 0, 383, "", 1, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("だからそんな顔しないの\nほら、お祝いの準備、進めるわよ！", "キャル", 106001, 16, 0, 384, "", 0, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("みんな…そうね\n最高のお祝いにして\n最高の思い出にしましょう！", "シェフィ", 106401, 12, 0, 385, "", 2, 0, 0, 80005, 4);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まで、あと10日！\nもうすぐですよー！\n楽しみすぎて、やばいですね！", "ペコリーヌ", 105801, 13, 0, 386, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そういえば…たくさんのおもちゃが\n子どもたちを襲うっていう\n騒動もありましたね…\nなんでも勝手に動き出したとか！", "ペコリーヌ", 105801, 14, 0, 387, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("学校や孤児院とかに\nちっちゃなおもちゃが乗り込んで\n暴れたみたいですよ！", "ペコリーヌ", 105801, 15, 0, 388, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("暴れたって言っても\n所詮はおもちゃじゃない\nどうせちっさいんでしょ？", "キャル", 106001, 17, 0, 389, "", 0, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("だったら魔法で\n全部ぶっ飛ばせばいいじゃない！\n大したことないわよ！", "キャル", 106001, 18, 0, 390, "", 0, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルってば…\n相手は子どもが\n大事にしてる物なのよ…？", "シェフィ", 106401, 13, 0, 391, "", 2, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("乱暴な発言は\nめっ、でございますよ？\n子どもの教育に悪影響を\n与えてしまいますから…", "コッコロ", 105901, 13, 0, 392, "", 1, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルちゃんだって\n意外と猫グッズとか\nたっくさん集めてますよね？\nもしその子たちが暴れたら…？", "ペコリーヌ", 105801, 16, 0, 393, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("う、うっさいわね！\n意外とか言うな！\n…ま、まあ確かに正面切って\n魔法でぶっ飛ばせないかもね…", "キャル", 106001, 19, 0, 394, "", 0, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あはは☆\nキャルちゃんのそういうところ\n好きですよ♪", "ペコリーヌ", 105801, 17, 0, 395, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そんなキャルちゃんに猫グッズを\nプレゼントしちゃいますね！\n一部で流行っていた、たい焼き屋の\nおまけフィギュアですよ♪", "ペコリーヌ", 105801, 18, 0, 396, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("乱暴に扱ったりしないでくださいね\nひとりでに暴れ出しちゃうかも\nしれませんから！", "ペコリーヌ", 105801, 19, 0, 397, "", 3, 0, 0, 80005, 5);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと９日\nここでみなさんに\nビックニュースですよ！", "カリン", 190801, 4, 0, 398, "", 2, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年を祝う生放送に\n去年と同様【美食殿】の\nみなさんにご出演いただくことが\n決定しましたー！", "カリン", 190801, 5, 0, 399, "", 2, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…えっ！？", "キャル", 106001, 20, 0, 400, "", 1, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("本当ですか！？\nそれじゃ今から張り切って\n生放送中に食べる魔物料理を\n作らなくちゃですね☆", "ペコリーヌ", 105801, 20, 0, 401, "", 3, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("いや…がんばるところは\nそこじゃないような…\nというか去年も出演してたのね\nすごいじゃない！", "シェフィ", 106401, 14, 0, 402, "", 0, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい。とても緊張しますが\nやりがいのある大役です\n一緒にがんばりましょうね\nシェフィさま", "コッコロ", 105901, 14, 0, 403, "", 4, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わ、私も出るの！？　でも…\n私も【美食殿】の一人だものね\nそれなら今からしっかり準備をして\nコンディションを整えないと…", "シェフィ", 106401, 15, 0, 404, "", 0, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふん♪\n生放送直前のカチコチになった\nシェフィの姿が楽しみだわ！", "キャル", 106001, 21, 0, 405, "", 1, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("去年のキャルちゃんは\n緊張しすぎてずっと震えて\nかわいかったですもんね！\n今年もあの姿が見たいです！", "ペコリーヌ", 105801, 21, 0, 406, "", 3, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ぶっ殺すぞ！？", "キャル", 106001, 22, 0, 407, "", 1, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("というわけで\n『プリンセスコネクト！\nRe:Dive』の魅力を\nお伝えする生放送をお楽しみに♪", "カリン", 190801, 6, 0, 408, "", 2, 0, 0, 80005, 6);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと８日\nでございますよ\n楽しみですね、主さま", "コッコロ", 105901, 15, 0, 409, "", 1, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("そういえばあんた\n夏休みの宿題は\nきちんとやってるの？", "キャル", 106001, 23, 0, 410, "", 0, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("宿題…学校に通うのも\n楽しいことばかりじゃ\nないのね", "シェフィ", 106401, 16, 0, 411, "", 2, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あれ？　そういえば\n少し前にルーセント学院で\n何かあったような…", "ペコリーヌ", 105801, 22, 0, 412, "", 3, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ああ、始業式の日に\n大捕り物があったって\n話題になってたわね", "キャル", 106001, 24, 0, 413, "", 0, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("夏休みを終わらせないって\n騒いでたっていう話？\nあれ本当なの？\n都市伝説だと思ってたわ", "シェフィ", 106401, 17, 0, 414, "", 2, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("その一件ならよく存じ上げて\nおります。ですから主さま\n次の機会にはわたくしと一緒に\nがんばりましょう", "コッコロ", 105901, 16, 0, 415, "", 1, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("楽しそう…私も一緒にやりたいな\nママ…じゃ、じゃなくて！\nコッコロさん、私もまざっていい？", "シェフィ", 106401, 18, 0, 416, "", 2, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もちろんでございます\n仲良くお勉強いたしましょう", "コッコロ", 105901, 17, 0, 417, "", 1, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("しれっと教育ママが\n生まれてる…？", "キャル", 106001, 25, 0, 418, "", 0, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お勉強は大切ですよ！\nキャルちゃんも一緒に\nがんばりましょう！", "ペコリーヌ", 105801, 23, 0, 419, "", 3, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("え～～～～！？", "キャル", 106001, 26, 0, 420, "", 0, 0, 0, 80005, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと７日〜♪\nふふ～ん♪\nふんふふ～ん♪", "キャル", 106001, 27, 0, 421, "", 0, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…\nねぇコッコロさん\nキャル、どうしちゃったの？", "シェフィ", 106401, 19, 0, 422, "", 2, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("とてもご機嫌そうに\n鼻歌を歌ってらっしゃいますね\n耳も尻尾もリズミカルに\n揺れて…ノリノリでございます", "コッコロ", 105901, 18, 0, 423, "", 1, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あれはですね！\nカルミナのみなさんの\nサマーライブのチケットが\n手に入ったからなんですよ♪", "ペコリーヌ", 105801, 24, 0, 424, "", 3, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええっ！？\nあのライブのチケットって確か\n入手困難だったんじゃ…", "シェフィ", 106401, 20, 0, 425, "", 2, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふふふ～ん♪\nしゃいにんぐふゅ～ちゃ～♪", "キャル", 106001, 28, 0, 426, "", 0, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なるほど…\nキャルさまがあのように\nなってしまうのも頷けますね", "コッコロ", 105901, 19, 0, 427, "", 1, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…カルミナの\n『Shining Future』\nの中に、シャイニングフューチャー\nって歌詞はなかったはずだけど…", "シェフィ", 106401, 21, 0, 428, "", 2, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふんふ…はっ！？\nあっ、あんたたち！\nなに人の鼻歌を\n勝手に聞いてるのよ！？", "キャル", 106001, 29, 0, 429, "", 0, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("こっ、これは別に\nカルミナの曲じゃなくて…\nあたしのオリジナルソングよ！\n聞いたらお金取るわよっ！？", "キャル", 106001, 30, 0, 430, "", 0, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えへへ、キャルちゃん\nカルミナのサマーライブ\n思いっきり楽しみましょうね☆", "ペコリーヌ", 105801, 25, 0, 431, "", 3, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("も～っ！\n生暖かい目で見るな～～！\nぶっ殺すわよ～～～！", "キャル", 106001, 31, 0, 432, "", 0, 0, 0, 80005, 8);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと６日\n３人も言ってたけど\nあっという間だったわね", "シェフィ", 106401, 22, 0, 433, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…えっ？\n生放送の意気込み！？\n突然なに！？", "シェフィ", 106401, 23, 0, 434, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええと…\nとにかく失敗しないように\n台本たくさん読んで…\nそれから…", "シェフィ", 106401, 24, 0, 435, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっ！？\nトラブルがあったら\nどうするのかって！？\nそ、それは…！", "シェフィ", 106401, 25, 0, 436, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("とにかく落ち着いて\nスタッフさんの指示を聞いて…", "シェフィ", 106401, 26, 0, 437, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それから、それから…！\nぅ、ぅぅっ…！", "シェフィ", 106401, 27, 0, 438, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("―びえぇぇ～んっ！！！", "シェフィ", 106401, 28, 0, 439, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("どうされましたか、シェフィさま", "コッコロ", 105901, 20, 0, 440, "", 1, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ううっ…ひっく…\nママッ…！", "シェフィ", 106401, 29, 0, 441, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("よしよし、緊張されてるのですね\nママが傍におりますよ\n主さま、少々お待ちくださいませ", "コッコロ", 105901, 21, 0, 442, "", 1, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…ふぅ\nシェフィさま\n生放送への意気込み\nお話しできそうですか？", "コッコロ", 105901, 22, 0, 443, "", 1, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…ううっ\n恥ずかしすぎて\nもう生放送出られない…", "シェフィ", 106401, 30, 0, 444, "", 0, 0, 0, 80005, 9);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("主さま\n3.5周年まであと５日\nでございます", "コッコロ", 105901, 23, 0, 445, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですがその前に\n生放送がありますね", "コッコロ", 105901, 24, 0, 446, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…生放送に向けた\n意気込みでございますか？", "コッコロ", 105901, 25, 0, 447, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もちろんわたくしは\n主さまのために\n全身全霊を込めて\n楽しい時間をご提供いたします", "コッコロ", 105901, 26, 0, 448, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…と、意気込んでみましたが\nうまくできるか少し不安です\n声が小さくなったり\n間違えてしまったらどうしようと…", "コッコロ", 105901, 27, 0, 449, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですがわたくしは\n一人ではありません\n【美食殿】のみなさまが\nおります", "コッコロ", 105901, 28, 0, 450, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("どんな困難も\nみなさまと一緒なら\n乗り越えられると\nわたくし、確信しております", "コッコロ", 105901, 29, 0, 451, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それに今回はシェフィさまも\nご参加されるわけですし\nママとしてお手本に\nならねばなりませんね", "コッコロ", 105901, 30, 0, 452, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("主さま。3.5周年も\n食卓を囲んでいる時のような\n楽しい思い出を\n一緒に作りましょうね", "コッコロ", 105901, 31, 0, 453, "", 0, 0, 0, 80005, 10);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと４日！\nやばいですね☆", "ペコリーヌ", 105801, 26, 0, 454, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はいはい、やばいわね\nというかもうすぐ生放送だけど\nあんた準備はできてるの？", "キャル", 106001, 32, 0, 455, "", 1, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ばっちりオイッスー☆　ですよ！\n『王家の装備』も全開です！", "ペコリーヌ", 105801, 27, 0, 456, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あとは前回を超える\n最高のオイッスー☆　を\nお届けできるように\n練習あるのみですかね！", "ペコリーヌ", 105801, 28, 0, 457, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("キャルちゃんは\nどうなんですか？\nオイッスー☆　を\n毎日ちゃんと練習してますか？", "ペコリーヌ", 105801, 29, 0, 458, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はぁ！？　なんであたしまで\nその変なあいさつを練習しないと\nいけないのよ！", "キャル", 106001, 33, 0, 459, "", 1, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もしかしてやってないんですか？\nダメですよキャルちゃん！\nシェフィちゃんだってちゃんと\n毎日練習してるのに！", "ペコリーヌ", 105801, 30, 0, 460, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("こうなったらわたしがキャルちゃん\nにオイッスー☆　の『オ』から\nしっかり教えてあげないと！", "ペコリーヌ", 105801, 31, 0, 461, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆　の『オ』は\n口を大きく開いて〜\nドラゴンの骨つき肉に\nかぶりつく直前をイメージして〜", "ペコリーヌ", 105801, 32, 0, 462, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("だからあたしはやるなんて一言も…", "キャル", 106001, 34, 0, 463, "", 1, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("オイッスー☆", "ペコリーヌ", 105801, 33, 0, 464, "", 0, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("聞きなさいっての！！", "キャル", 106001, 35, 0, 465, "", 1, 0, 0, 80005, 11);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと３日…\nそして生放送は、明日…", "シェフィ", 106401, 31, 0, 466, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("もっと台本を\n読み込んでおかないと…\nあと発声練習も…", "シェフィ", 106401, 32, 0, 467, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おいっす！\n…こうじゃなかったわね\nええと確か…", "シェフィ", 106401, 33, 0, 468, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("うう…あんなに練習したのに\nこれじゃみんなに迷惑かけちゃう…", "シェフィ", 106401, 34, 0, 469, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("【美食殿】の一員として\n認められるように\n頑張らないといけないのに\nよし、もう一度…", "シェフィ", 106401, 35, 0, 470, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("やってますねシェフィちゃん！", "ペコリーヌ", 105801, 34, 0, 471, "", 3, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なによ、考えることは\nみんな同じってこと？", "キャル", 106001, 36, 0, 472, "", 0, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ。シェフィさま\nよろしければ\n仲間に入れてください\n一緒にやればきっとうまくできます", "コッコロ", 105901, 32, 0, 473, "", 1, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("みんな…もちろんよ！", "シェフィ", 106401, 36, 0, 474, "", 2, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それじゃ明日の生放送に向けて\n一緒に練習がんばりましょう☆", "ペコリーヌ", 105801, 35, 0, 475, "", 3, 0, 0, 80005, 12);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年まであと２日と\n迫った本日は…\nいよいよ生放送です！", "カリン", 190801, 7, 0, 476, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("【美食殿】のみなさんが\n準備に入られていますので\nそれぞれ繋いでみましょう！\nまずはペコリーヌさんです！", "カリン", 190801, 8, 0, 477, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日もオイッスー☆\nみんなで一緒に\nオイッスー☆", "ペコリーヌ", 105801, 36, 0, 478, "", 3, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("お手本になるような\n発声練習ですね！\nそれでは続いてコッコロさん", "カリン", 190801, 9, 0, 479, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はじめちょろちょろ\nなかぱっぱ～♪\n生放送前にみなさまで\n食卓を囲んで英気を養いましょう", "コッコロ", 105901, 33, 0, 480, "", 4, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("さすが【美食殿】のママですね！\nそしてキャルさんは…", "カリン", 190801, 10, 0, 481, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("大丈夫…大丈夫…\nあたしは大丈夫…", "キャル", 106001, 37, 0, 482, "", 1, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("す、すごく震えてますけど\n大丈夫でしょうか…？\nそして今回初参加となる\n期待の新人シェフィさん！", "カリン", 190801, 11, 0, 483, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あうー？", "シェフィ", 106401, 37, 0, 484, "", 0, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("あ…", "みんな", 105801, 37, 0, 485, "105901,34,106001,38,190801,12", 4, 1, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ちょ、ちょっとシェフィ！？\nなに赤ちゃん返りしてん―\nあ痛ぁっ！\n噛んだわこいつーっ！", "キャル", 106001, 39, 0, 486, "", 1, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("シェフィさま\n緊張しすぎて\nしまったのでしょうね…\nおーよしよし…", "コッコロ", 105901, 35, 0, 487, "", 4, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("シェフィちゃん！\nそういう時は手のひらに\n好きな文字を書いて\n食べちゃうといいですよ！", "ペコリーヌ", 105801, 38, 0, 488, "", 3, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("…ええと、現場からは以上です！\n生放送はもうすぐ！\n特別なお知らせもありますので\nどうぞお楽しみに！", "カリン", 190801, 13, 0, 489, "", 2, 0, 0, 80005, 13);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年の記念日も\nいよいよ明日ね\n…って、あれ？", "シェフィ", 106401, 38, 0, 490, "", 2, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("記念日はこの森へ行きませんか！？\nすっごく美味しいお肉が\nとれるんです☆", "ペコリーヌ", 105801, 39, 0, 491, "", 3, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("うげ、またあの魔物？\nさすがに今度は\n丸焼きとかはやめてよね…\n見た目がヤバすぎるし", "キャル", 106001, 40, 0, 492, "", 0, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふ、キャルさまもだいぶ\n魔物肉に慣れてきたようですね\n調理ならばわたくしに\nお任せください♪", "コッコロ", 105901, 36, 0, 493, "", 1, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("みんな、何をしているの？\nなんだか、\n不穏な単語が聞こえたんだけど…", "シェフィ", 106401, 39, 0, 494, "", 2, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("シェフィちゃん！\n明日の食べ尽くしツアーの\n相談をしてたんですよ！", "ペコリーヌ", 105801, 40, 0, 495, "", 3, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("はい。明日は【美食殿】の\n一員となったシェフィさまと一緒に\n初めて記念日を過ごすのですから\n特別なコース料理を用意しませんと", "コッコロ", 105901, 37, 0, 496, "", 1, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ふふん♪\n猫の毛も逆立つような\nあれこれを食べさせられるから\n覚悟しておいたほうがいいわよ？", "キャル", 106001, 41, 0, 497, "", 0, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("へ、へぇ…", "シェフィ", 106401, 40, 0, 498, "", 2, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("期待しててくださいね！\nシェフィちゃんとあなたに\n『おいちー！』って喜んでもらえる\n最高のごちそうを準備しますから☆", "ペコリーヌ", 105801, 41, 0, 499, "", 3, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええと…その…うーんと…\nわ、分かったわ\n私も【美食殿】の一員だもの", "シェフィ", 106401, 41, 0, 500, "", 2, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それにあなたも一緒みたいだし\n最後までがんばってみるわ…！", "シェフィ", 106401, 42, 0, 501, "", 2, 0, 0, 80005, 14);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それではいつものあれを\nやりましょう！\n準備はいいですかっ？\n…いっきますよー！", "ペコリーヌ", 105801, 42, 0, 502, "", 3, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("祝！", "キャル", 106001, 42, 0, 503, "", 1, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("3.5周年！", "コッコロ", 105901, 38, 0, 504, "", 4, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おめでとうございます！", "シェフィ", 106401, 43, 0, 505, "", 0, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("この日を迎えられたのも\nあなたが『プリンセスコネクト！\nRe:Dive』を遊んでくれている\nおかげです！", "カリン", 190801, 14, 0, 506, "", 2, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ということで\nみなさんからあなたへ一言ずつ\n感謝の言葉をどうぞ！", "カリン", 190801, 15, 0, 507, "", 2, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("感謝の言葉ですか？　わたしは\n毎日あなたに感謝してますよ\n【美食殿】の仲間になってくれて…\n一緒にごはんを食べてくれて…", "ペコリーヌ", 105801, 43, 0, 508, "", 3, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("なにより今でもわたしをぺコリーヌ\nって呼んでくれてありがとうござい\nます。これからもわたしはあなたの\nぺコリーヌです！　やばいですね☆", "ペコリーヌ", 105801, 44, 0, 509, "", 3, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("えっ！？　今度はあたし！？\n感謝って…まぁ、そうね…\nあんたにはあたしが\n辛くて苦しい時に助けてもらって…", "キャル", 106001, 43, 0, 510, "", 1, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("でもおかげで色々吹っ切れたわ！\nもしあんたが困ってたら今度は\nあたしが助けてあげるから\nその時はちゃんと言いなさいよ！", "キャル", 106001, 44, 0, 511, "", 1, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ええと…次は私ね\n実はよく覚えてないのだけど\n空から落ちてきた私を受け止めて\nくれたのはあなたなのでしょう？", "シェフィ", 106401, 44, 0, 512, "", 0, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("最初に私を見つけてくれたのが\nあなたで良かったって思ってるの\nおかげで私は居場所を見つけたから\nあなたがくれたもの、大切にするわ", "シェフィ", 106401, 45, 0, 513, "", 0, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("では最後にわたくしから…\nわたくしは主さまの元を離れた日…\nこのように記念日をお祝いする\nことは二度とないと思っていました", "コッコロ", 105901, 39, 0, 514, "", 4, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("ですが、主さまはわたくしを\n迎えにきてくださり、今もこうして\nおそばにおいてくださっています\nわたくしにとって毎日が記念日です", "コッコロ", 105901, 40, 0, 515, "", 4, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("わたくしたちの物語は\nまだ続いていきます\nこれからも一緒にページを\n作っていきましょうね", "コッコロ", 105901, 41, 0, 516, "", 4, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("それじゃ\nいつものあれでしめますよ！\nみんなで一緒に、さんはい☆", "ペコリーヌ", 105801, 45, 0, 517, "", 3, 0, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("これからも\nよろしくおねがいします！", "みんな", 105801, 46, 0, 518, "105901,42,106001,45,106401,46,190801,16", 4, 1, 0, 80005, 15);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", "カリン", 190804, 1, 0, 519, "", 1, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　どんな不可能も可能にできちゃう！　　　　仲間と食卓を囲めばさらに運気上昇よ！　ただし魔物料理以外！", "", 0, 0, 1, 520, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 521, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", "", 0, 0, 1, 522, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　精霊も新年の幸福をお祝いしています！　　主さまの笑顔が見られて、わたくしも幸せいっぱいでございます♪", "", 0, 0, 1, 523, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", "", 0, 0, 1, 524, "", 2, 0, 2, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　お裁縫好きな女の子のお墨付きです！　　　お世話したがりの妹にめいっぱい愛されちゃうかも！？", "", 0, 0, 2, 525, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", "", 0, 0, 2, 526, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーカラーは鮮やかな黄色！　　　　　さらにシマシマのアイテムを持つと、運気倍増らしいッスよ♪", "", 0, 0, 2, 527, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", "", 0, 0, 2, 528, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", "", 0, 0, 2, 529, "", 2, 0, 2, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　家の中でゆっくり過ごすのがよさそう！　　ラッキーアイテムはゲームよ！　ベストスコアを更新できるかも？", "", 0, 0, 3, 530, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　上手くなりたいことに積極的に挑戦してみてサックス好きの妹が、手取り足取りサポートしてくれるかも～？", "", 0, 0, 3, 531, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　仕事運が急上昇中です！　　　　　　　　　きっと「煉獄に舞う一陣の疾風」の如き活躍ができますよ！", "", 0, 0, 3, 532, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　日頃の努力が報われます！　　　　　　　　親しい友人がいるなら報告してみて。一緒に喜んでくれるはずだ。", "", 0, 0, 3, 533, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　ラッキーアイテムはかわいいもの！　　　　ア、アタシはかわいいじゃなくてキレイだってば！　も～っ！", "", 0, 0, 3, 534, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　チャンスを待つと良い結果に！　　　　　　ラッキーアイテムのプリンを食べて、運を呼び込みましょう！", "", 0, 0, 3, 535, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　悩まず行動すれば強運に恵まれる！　　　　守るよりも攻めるが吉だ！　勝負事をするにはいい運勢だな！", "", 0, 0, 3, 536, "", 2, 0, 2, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　まだ見ぬ危険が隠れているかも！　　　　　でも安心しろ！　提督が貴公を守ってくれるはずだぞ！", "", 0, 0, 4, 537, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", "", 0, 0, 4, 538, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", "", 0, 0, 4, 539, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", "", 0, 0, 4, 540, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　同腹一心の友だちが見つかるかも！　　　　キーワードは「ユニちゃんズ」、記憶に刻みましょう！", "", 0, 0, 4, 541, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", "", 0, 0, 4, 542, "", 2, 0, 1, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　無理は禁物、お家で静かにしていましょう　プロぼっちの私が、お家での過ごし方……教えてあげましょうか？", "", 0, 0, 4, 543, "", 2, 0, 2, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", "カリン", 190804, 2, 0, 544, "", 3, 0, 0, 60003, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", "カリン", 190804, 3, 0, 545, "", 3, 0, 0, 60003, 7);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", "カリン", 190804, 1, 0, 546, "", 1, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 547, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　羽が生えたように飛躍できる絶好調の運気！新しいことに挑戦するなら今しかないわ！　やってみましょう！", "", 0, 0, 1, 548, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　宴でも開きたくなるほどの絶対幸運！\nイメチェンでもしてみるのはどうだ？　ぴょんぴょん、なんてな♪", "", 0, 0, 1, 549, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", "", 0, 0, 1, 550, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが上手くいく最高の一日！　　あなたの活躍に先生もにっこりです。いい子いい子♪", "", 0, 0, 1, 551, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　悩んでいたことが解決しそうです！　　　　たまには勉強も仕事も忘れて、心あたたまる家族と過ごしましょ！", "", 0, 0, 2, 552, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーカラーは赤！　　　　　　　　　　湧き上がるアイデアの数々に、高笑いが止まりませんわ！", "", 0, 0, 2, 553, "", 2, 0, 2, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーワードは「ぴょんぴょん♪」\nおっきな声で一緒に言ってみよ～♪　うさぎさんぴょんぴょ～ん♪", "", 0, 0, 2, 554, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　あなたの趣味がもっと広がるかも！\nかんわゆ～～～いショタと～騎士きゅんもゲット～んふふ～♪", "", 0, 0, 2, 555, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　秘められた力が開花するでしょう！　　　　じゃあ、私の龍眼と力比べしてみようか？　ふふ、冗談だよ～", "", 0, 0, 2, 556, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　ラッキーアイテムはかわいいもの！　　　　ア、アタシはかわいいじゃなくてキレイだってば！　も～っ！", "", 0, 0, 3, 557, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　悩まず行動すれば強運に恵まれる！　　　　守るよりも攻めるが吉だ！　勝負事をするにはいい運勢だな！", "", 0, 0, 3, 558, "", 2, 0, 2, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　お出かけした先で良縁に恵まれそうです！　ダウナー系あざとい女子が、あま～い飴をくれるかも？", "", 0, 0, 3, 559, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　大抵のことはゴリ押しでなんとかできます！ラッキープレイスはゲーセン。パンチングマシンでストレス発散！", "", 0, 0, 3, 560, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　健康に気を遣って気持ちのいい一年を！\n体に不調があるときは遠慮なく言いなさい、隅々まで調べてあげる", "", 0, 0, 3, 561, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　歌を口ずさみ、幸運を呼び込もう！\n幸運になれるかは分からないけど……一緒に、歌いましょ？", "", 0, 0, 3, 562, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　誰かに尽くすことで掴める幸せもあるかも？\n人事を尽くして天命を待つ！　さ、年始もバリバリ働きますわよ♪", "", 0, 0, 3, 563, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　難しい頼み事をされるかもしれません！　　うまくやれればきっと成長につながります、挑戦してみましょう！", "", 0, 0, 4, 564, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　無理は禁物、お家で静かにしていましょう　プロぼっちの私が、お家での過ごし方……教えてあげましょうか？", "", 0, 0, 4, 565, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　思わぬ相手と仲良くなれるかも？　　　　　うっかり毒舌をもらしてしまわないように要注意です！", "", 0, 0, 4, 566, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　いろんな事件が起こる一日になりそう！　　状況をよく観察してみようじゃないか！　まさに探偵のごとくね！", "", 0, 0, 4, 567, "", 2, 0, 2, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　周りに流されず、マイペースな一日を！　　ただし寝すぎには注意ぐうたらし過ぎず適度な運動を、だってさ～", "", 0, 0, 4, 568, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？", "", 0, 0, 4, 569, "", 2, 0, 1, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　小さな勇気で踏み出す一歩が大事！\n遠くから見てるだけじゃダメ。今日は、少しだけ近づいてみます！", "", 0, 0, 4, 570, "", 2, 0, 2, 60004, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", "カリン", 190804, 2, 0, 571, "", 3, 0, 0, 60004, 0);
