INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("新年を迎え、新たに始まる一日を\nおみくじで占ってみませんか？\n良い運勢であるほど、\n沢山のプレゼントが貰えますよ♪", "カリン", 190804, 1, 0, 573, "", 1, 0, 1, 60005, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　やること全てが最高潮！　やばいですね☆　ラッキーアイテムはおにぎり！　お腹一杯で幸せが続くでしょう！", "", 0, 0, 1, 574, "", 2, 0, 1, 60005, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　ずっと祈り続けていた願いが叶うかも！\nきっとあんたならたどり着けるわ、ハッピーエンドのその先に", "", 0, 0, 1, 575, "", 2, 0, 1, 60005, 0);
