INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　どんなピンチも簡単に乗り越えられそう！\nよい結果が出たようで何よりです。さて、待人の方は……ふふ。", "", 0, 0, 1, 602, "", 2, 0, 2, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　あの人と仲直り……できちゃうかも！？\nはあ……この私があなたの運勢に興味を抱くわけないでしょう？", "", 0, 0, 1, 603, "", 2, 0, 2, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　身近な友達との絆が深まる予感……？\n騎士様は、どなたと友誼を結ぶのでしょう？　気になります……", "", 0, 0, 2, 604, "", 2, 0, 1, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　ラッキーアイテムは「蛇の抜け殻」！\nこのアタシにお目にかかれるなんて……アンタ、幸せものね♪", "", 0, 0, 2, 605, "", 2, 0, 2, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　気になるあの人に会えちゃうかも！？\n『初夢を正夢にする枕』であなたに会え……な、なんでもない！", "", 0, 0, 3, 606, "", 2, 0, 2, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　子供に戻って、一日中遊びつくそう！\nお年玉でけん玉ゲット！　おじちゃん、もしかめ一万回やって！", "", 0, 0, 3, 607, "", 2, 0, 2, 60006, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　今日はおうちで、ゆーっくりくつろごう。\nお雑煮よし。みかんよし。さ、こたつで寝正月だ。君も入る？", "", 0, 0, 3, 608, "", 2, 0, 1, 60006, 0);
