INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　絶好調で最高の一日になりそう♪\nわたしも、騎士クンが一緒ならいつだって最高に幸せな日だよ……", "", 0, 0, 1, 614, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　新しいことに挑戦するチャンス！\nお姉さんも一緒に挑戦しちゃおっかな♪　飲み処の新規開拓とか！", "", 0, 0, 1, 615, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は姫吉！　日々の努力が実を結ぶ予感！\n今日一日鍛錬に勤しむべき、ということだな。では早速行こうか。", "", 0, 0, 1, 616, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　家族サービスにはぴったりの日！\nさっそく弟くんにあまあまお姉ちゃんの出血大サービス、だよっ♪", "", 0, 0, 2, 617, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は大吉！　笑顔で過ごせば周りもみんなハッピーかも！\n『笑う顔はフグになる』ですねっ。幸せいっぱいお届けしますっ", "", 0, 0, 2, 618, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　恋愛運良し、積極的な行動に成果が！？\nじゃあ騎士さんのこと、拉致しちゃうとか★　恋愛成就確定です♥", "", 0, 0, 3, 619, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は中吉！　おめかししたら運気も上昇？\n毛並がふわふわになるまでブラッシングしたわ♪　ふふ、完璧ね！", "", 0, 0, 3, 620, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　知らない場所に行くと新たな発見が！\n未知の場所……一人では恐ろしくて。騎士さま、どうかお力添えを", "", 0, 0, 4, 621, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("今日の運勢は小吉！　ラッキーアイテムは鳥の羽根！\nだからって、私の羽を毟ろうとしないでくださ～いっ！", "", 0, 0, 4, 622, "", 2, 0, 2, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじの結果はどうでしたか？\n新たに始まる一日が、あなたに\nとって良い日になりますように\nまた明日も遊びに来て下さいね♪", "カリン", 190804, 2, 0, 623, "", 3, 0, 0, 60007, 0);
INSERT INTO `v1_e6cc43561b356d60aca52668dc232171588554034183a87ffda8d4c0ccc89126` VALUES ("おみくじは楽しんで頂けましたか？\nあなたの新たなる年が\n素晴らしいものになるよう、\n心からお祈りいたします", "カリン", 190804, 3, 0, 624, "", 3, 0, 0, 60007, 5);
